  const page = await browser.newPage({ viewport: { width: 1280, height: 720 } });
  const url = "file:///" + VIDEO.replace(/\\/g, "/");
  await page.setContent(`
    <html><body style="margin:0;background:#0a1f3d;display:grid;place-items:center;height:100vh">
    <video id="v" muted playsinline style="width:100vw;height:100vh;object-fit:contain" src="${url}"></video>
    <script>
