async function patchPptx(file) {
  const buf = fs.readFileSync(file);
  const zip = await JSZip.loadAsync(buf);
  const slideNames = Object.keys(zip.files).filter((n) => /^ppt\/slides\/slide\d+\.xml$/.test(n));
  for (const name of slideNames) {
    let xml = await zip.file(name).async("string");
    if (!xml.includes("<p:transition")) {
      xml = xml.replace("</p:sld>", '<p:transition spd="med"><p:fade/></p:transition></p:sld>');
    }
    if (name.endsWith("slide12.xml")) {
      const mediaMatch = xml.match(/<p:cNvPr id="(\d+)" name="Media [^"]*">/);
      const spid = mediaMatch ? mediaMatch[1] : "3";
      const timing = `<p:timing><p:tnLst><p:par><p:cTn id="1" dur="indefinite" restart="never" nodeType="tmRoot"><p:childTnLst><p:video><p:cMediaNode vol="0"><p:cTn id="2" fill="hold" display="0"><p:stCondLst><p:cond delay="0"/></p:stCondLst></p:cTn><p:tgtEl><p:spTgt spid="${spid}"/></p:tgtEl></p:cMediaNode></p:video></p:childTnLst></p:cTn></p:par></p:tnLst></p:timing>`;
      if (!xml.includes("<p:timing>")) {
        xml = xml.replace("</p:sld>", `${timing}</p:sld>`);
      }
    }
    zip.file(name, xml);
  }
  const out = await zip.generateAsync({ type: "nodebuffer" });
  fs.writeFileSync(file, out);
}

