function setFonts(xml) {
  return xml.replace(/<a:rPr\b([^>]*)>([\s\S]*?)<\/a:rPr>/g, (whole, attrs, inner) => {
    const sz = Number((attrs.match(/\bsz="(\d+)"/) || [0, "0"])[1]);
    let font = "Microsoft YaHei UI";
    if (sz >= 2400) font = "Microsoft YaHei UI Light";
    if (sz <= 850 && whole.includes("Consolas")) font = "Bahnschrift Light";
    if (whole.includes("rospy") || whole.includes("goal_pubs") || whole.includes("map_dir") || whole.includes("Subscriber")) font = "Consolas";
    inner = inner
      .replace(/<a:latin[^/]*\/>/, `<a:latin typeface="${font}"/>`)
      .replace(/<a:ea[^/]*\/>/, `<a:ea typeface="${font}"/>`)
      .replace(/<a:cs[^/]*\/>/, `<a:cs typeface="${font}"/>`);
    return `<a:rPr${attrs}>${inner}</a:rPr>`;
  });
}

function replaceText(xml, from, to) {
  const esc = from.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  return xml.replace(new RegExp(`(<a:t>)${esc}(</a:t>)`, "g"), `$1${to}$2`);
}

function polishTextXml(xml, slideNum) {
  xml = setFonts(xml);
  const replacements = [
    ["ROS COURSE PROJECT · FINAL REPORT", "ROS NOETIC · GROUP PROJECT"],
    ["PROJECT CONTEXT · 任务背景", "PROJECT BACKGROUND · 任务背景"],
    ["我们实际做出的东西", "最终系统实现"],
    ["从演示结果倒推系统结构", "最终成果概览"],
    ["展示核心机制，避免源码堆叠", "核心代码与职责划分"],
    ["DEMO SCRIPT · 汇报顺序", "SYSTEM CHECK · 联调验证"],
    ["现场怎么讲更顺", "运行结果、架构与代码的闭环验证"],
    ["演示时不要先讲代码，先让大家看到结果", "系统验证围绕运行结果、系统架构、核心代码与流程记录展开"],
    ["先展示 RViz 截图", "RViz 轨迹验证"],
    ["再讲系统结构", "系统结构验证"],
    ["最后回到代码", "核心代码验证"],
    ["播放流程视频", "流程视频验证"],
    ["用视频收尾，证明系统不是静态截图，而是完整运行过程。", "通过视频记录完整运行过程，补充截图无法呈现的动态细节。"],
    ["TONE", "CHECKPOINT"],
    ["讲法尽量像小组复盘：我们遇到了什么问题、怎么改、最后跑出了什么结果。这样比堆术语更像真实作业汇报。", "联调材料包括运行截图、节点关系、核心代码与完整流程视频，能够支撑最终成果展示。"],
    ["结果先行，再讲架构和代码", "运行结果 · 架构 · 代码 · 流程"],
    ["SCRIPT", "CHECK"],
    ["KEY POINT", "PATH TRACE"],
    ["TAKEAWAY", "RESOLUTION"],
    ["这次作业的重点，是把 ROS 组件组织成一个真正能运行的任务系统", "通过 ROS 节点协作完成多机器人搜救任务闭环"],
    ["最后收束到课程收获", "项目总结"],
  ];
  for (const [a, b] of replacements) xml = replaceText(xml, a, b);
  if (slideNum === 11) {
    xml = replaceText(xml, "Q & A", "THANKS");
  }
  return xml;
}

function ensurePngContentType(zip) {
  return zip.file("[Content_Types].xml").async("string").then((xml) => {
    if (!xml.includes('Extension="png"')) {
      xml = xml.replace("</Types>", '<Default Extension="png" ContentType="image/png"/></Types>');
    }
    zip.file("[Content_Types].xml", xml);
  });
}

