const fs = require("fs");
const path = require("path");
const { createRequire } = require("module");
const req = createRequire("C:/Users/Aieyr/.cache/codex-runtimes/codex-primary-runtime/dependencies/node/node_modules/");
const JSZip = req("jszip");
const sharp = req("sharp");

const ROOT = __dirname;
const PPT = path.join(ROOT, "ROS多机器人协同搜救系统_小组汇报_最终润色版.pptx");
const ASSET = path.join(ROOT, "ppt", "online_assets");
const IMG = path.join(ROOT, "ppt", "images");
const RVIZ = path.join(IMG, "10-rviz-result.png");
const TURTLE = path.join(ASSET, "turtlebot3_burger.jpg");

function replaceText(xml, from, to) {
  const esc = from.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  return xml.replace(new RegExp(`(<a:t>)${esc}(</a:t>)`, "g"), `$1${to}$2`);
}

function replaceAllText(xml, pairs) {
  for (const [a, b] of pairs) xml = replaceText(xml, a, b);
  return xml;
}

async function makeSlide9Bg() {
  const W = 1600, H = 900;
  const base = Buffer.from(`
  <svg width="${W}" height="${H}" xmlns="http://www.w3.org/2000/svg">
    <defs>
      <linearGradient id="bg" x1="0" y1="0" x2="1" y2="1">
        <stop offset="0%" stop-color="#f3f1ea"/>
        <stop offset="48%" stop-color="#e5edf3"/>
        <stop offset="100%" stop-color="#0a1f3d"/>
      </linearGradient>
      <linearGradient id="shade" x1="0" y1="0" x2="1" y2="0">
        <stop offset="0%" stop-color="#f3f1ea" stop-opacity="0.88"/>
        <stop offset="56%" stop-color="#f3f1ea" stop-opacity="0.72"/>
        <stop offset="100%" stop-color="#0a1f3d" stop-opacity="0.55"/>
      </linearGradient>
    </defs>
    <rect width="1600" height="900" fill="url(#bg)"/>
    <g opacity="0.26">
      ${Array.from({length: 24}, (_, i) => `<line x1="${i*80-200}" y1="0" x2="${i*80+120}" y2="900" stroke="#0a1f3d" stroke-width="1"/>`).join("")}
      ${Array.from({length: 10}, (_, i) => `<line x1="0" y1="${90+i*78}" x2="1600" y2="${90+i*78}" stroke="#0a1f3d" stroke-width="1"/>`).join("")}
    </g>
    <circle cx="1370" cy="160" r="260" fill="#c8a24a" opacity="0.10"/>
    <circle cx="1260" cy="720" r="340" fill="#4a78c2" opacity="0.18"/>
  </svg>`);
  const comps = [];
  if (fs.existsSync(RVIZ)) {
    const rviz = await sharp(RVIZ)
      .resize(760, 428, { fit: "cover", position: "center" })
      .modulate({ saturation: 0.65, brightness: 1.02 })
      .ensureAlpha(0.18)
      .png()
      .toBuffer();
    comps.push({ input: rviz, left: 790, top: 85 });
  }
  if (fs.existsSync(TURTLE)) {
    const turtle = await sharp(TURTLE)
      .resize(520, 520, { fit: "cover", position: "center" })
      .modulate({ saturation: 0.7, brightness: 0.9 })
      .ensureAlpha(0.18)
      .png()
      .toBuffer();
    comps.push({ input: turtle, left: 1030, top: 360 });
  }
  const veil = Buffer.from(`<svg width="1600" height="900" xmlns="http://www.w3.org/2000/svg"><rect width="1600" height="900" fill="url(#shade)"/><defs><linearGradient id="shade" x1="0" y1="0" x2="1" y2="0"><stop offset="0%" stop-color="#f3f1ea" stop-opacity="0.92"/><stop offset="62%" stop-color="#f3f1ea" stop-opacity="0.72"/><stop offset="100%" stop-color="#0a1f3d" stop-opacity="0.35"/></linearGradient></defs></svg>`);
  comps.push({ input: veil, left: 0, top: 0 });
  return sharp(base).composite(comps).png().toBuffer();
}

function removeSlide12FromPresentation(zip) {
  return Promise.all([
    zip.file("ppt/presentation.xml").async("string"),
    zip.file("ppt/_rels/presentation.xml.rels").async("string"),
    zip.file("[Content_Types].xml").async("string"),
  ]).then(([pres, rels, ct]) => {
    pres = pres.replace(/<p:sldId id="268" r:id="rId18"\/>/, "");
    rels = rels.replace(/<Relationship Id="rId18" Type="http:\/\/schemas\.openxmlformats\.org\/officeDocument\/2006\/relationships\/slide" Target="slides\/slide12\.xml"\/>/, "");
    ct = ct.replace(/<Override PartName="\/ppt\/slides\/slide12\.xml" ContentType="application\/vnd\.openxmlformats-officedocument\.presentationml\.slide\+xml"\/>/, "");
    ct = ct.replace(/<Override PartName="\/ppt\/notesSlides\/notesSlide12\.xml" ContentType="application\/vnd\.openxmlformats-officedocument\.presentationml\.notesSlide\+xml"\/>/, "");
    zip.file("ppt/presentation.xml", pres);
    zip.file("ppt/_rels/presentation.xml.rels", rels);
    zip.file("[Content_Types].xml", ct);
  });
}

